<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\Storage;
use Symfony\Component\HttpFoundation\BinaryFileResponse;

class PdfReportController extends Controller
{
    /**
     * Valid page sizes supported by wkhtmltopdf.
     */
    private const VALID_PAGE_SIZES = [
        'A0', 'A1', 'A2', 'A3', 'A4', 'A5', 'A6', 'A7', 'A8', 'A9',
        'B0', 'B1', 'B2', 'B3', 'B4', 'B5', 'B6', 'B7', 'B8', 'B9', 'B10',
        'C5E', 'Comm10E', 'DLE', 'Executive', 'Folio',
        'Ledger', 'Legal', 'Letter', 'Tabloid',
    ];

    /**
     * Generate a PDF report using wkhtmltopdf.
     *
     * @param Request $request
     * @return BinaryFileResponse|\Illuminate\Http\JsonResponse
     */
    public function generate(Request $request)
    {
        $request->validate([
            'page_size' => ['required', 'string'],
            'filename' => ['required', 'string'],
            'html_content' => ['required', 'string'],
        ]);

        $pageSize = $request->input('page_size');
        $filename = $request->input('filename');
        $htmlContent = $request->input('html_content');

        // Validate page size against whitelist to prevent command injection
        if (!in_array($pageSize, self::VALID_PAGE_SIZES, true)) {
            return response()->json([
                'error' => 'Invalid page size. Allowed sizes: ' . implode(', ', self::VALID_PAGE_SIZES),
            ], 422);
        }

        // Sanitize filename: allow only alphanumeric, hyphens, underscores
        // Strip any directory traversal or dangerous characters
        $sanitizedFilename = preg_replace('/[^a-zA-Z0-9_\-]/', '', pathinfo($filename, PATHINFO_FILENAME));

        if (empty($sanitizedFilename)) {
            return response()->json([
                'error' => 'Invalid filename. Only alphanumeric characters, hyphens, and underscores are allowed.',
            ], 422);
        }

        // Limit filename length
        if (strlen($sanitizedFilename) > 100) {
            $sanitizedFilename = substr($sanitizedFilename, 0, 100);
        }

        // Create a unique temporary directory for this request
        $tempDir = storage_path('app/temp/pdf_' . uniqid('', true));
        if (!mkdir($tempDir, 0700, true) && !is_dir($tempDir)) {
            return response()->json(['error' => 'Failed to create temporary directory.'], 500);
        }

        $inputPath = $tempDir . DIRECTORY_SEPARATOR . 'input.html';
        $outputPath = $tempDir . DIRECTORY_SEPARATOR . $sanitizedFilename . '.pdf';

        try {
            // Write HTML content to a temporary file
            if (file_put_contents($inputPath, $htmlContent) === false) {
                return response()->json(['error' => 'Failed to write temporary HTML file.'], 500);
            }

            // Build the command using escapeshellarg for all dynamic parts
            $wkhtmltopdfBinary = config('pdf.wkhtmltopdf_path', '/usr/local/bin/wkhtmltopdf');

            // Verify the binary exists
            if (!file_exists($wkhtmltopdfBinary) || !is_executable($wkhtmltopdfBinary)) {
                return response()->json(['error' => 'wkhtmltopdf binary not found or not executable.'], 500);
            }

            // Page size is already validated against whitelist above, but we still escape it
            // All arguments are properly escaped using escapeshellarg
            $command = sprintf(
                '%s --page-size %s %s %s 2>&1',
                escapeshellarg($wkhtmltopdfBinary),
                escapeshellarg($pageSize),
                escapeshellarg($inputPath),
                escapeshellarg($outputPath)
            );

            $output = [];
            $returnCode = 0;

            exec($command, $output, $returnCode);

            if ($returnCode !== 0) {
                \Log::error('wkhtmltopdf failed', [
                    'return_code' => $returnCode,
                    'output' => implode("\n", $output),
                ]);

                return response()->json([
                    'error' => 'PDF generation failed.',
                    'details' => 'wkhtmltopdf exited with code ' . $returnCode,
                ], 500);
            }

            if (!file_exists($outputPath)) {
                return response()->json(['error' => 'PDF file was not created.'], 500);
            }

            // Return the PDF as a download, then clean up
            return response()
                ->download($outputPath, $sanitizedFilename . '.pdf', [
                    'Content-Type' => 'application/pdf',
                ])
                ->deleteFileAfterSend(true);

        } catch (\Exception $e) {
            \Log::error('PDF generation exception', [
                'message' => $e->getMessage(),
                'trace' => $e->getTraceAsString(),
            ]);

            return response()->json(['error' => 'An unexpected error occurred during PDF generation.'], 500);

        } finally {
            // Clean up temporary files
            if (file_exists($inputPath)) {
                @unlink($inputPath);
            }
            // Note: outputPath is deleted by deleteFileAfterSend if download succeeds
            // Clean up the temp directory if it's empty
            @rmdir($tempDir);
        }
    }

    /**
     * Return the list of valid page sizes.
